// ================================================================
// MAIN SEED FUNCTION
// ================================================================
async function main() {
  console.log('\n🇵🇰 RouteReady — Seeding Pakistan Tourism Database...\n');
  console.log(`   📍 Destinations : ${destinations.length}`);
  console.log(`   🏨 Hotels       : ${hotels.length}`);
  console.log(`   💎 Hidden Gems  : ${hiddenGems.length}`);
  console.log(`   📊 Total        : ${destinations.length + hotels.length + hiddenGems.length}\n`);

  console.log('🗑️  Clearing existing data...');
  await prisma.userSavedDestination.deleteMany();
  await prisma.review.deleteMany();
  await prisma.destination.deleteMany();
  await prisma.hotel.deleteMany();
  await prisma.hiddenGem.deleteMany();
  console.log('   ✓ Done\n');

  console.log('📍 Seeding destinations...');
  let d = 0;
  for (const item of destinations) {
    await prisma.destination.create({ data: item });
    d++;
    if (d % 25 === 0) process.stdout.write(`   ${d}/${destinations.length}\r`);
  }
  console.log(`\n   ✓ ${d} destinations\n`);

  console.log('🏨 Seeding hotels...');
  let h = 0;
  for (const item of hotels) {
    await prisma.hotel.create({ data: item });
    h++;
  }
  console.log(`   ✓ ${h} hotels\n`);

  console.log('💎 Seeding hidden gems...');
  let g = 0;
  for (const item of hiddenGems) {
    await prisma.hiddenGem.create({ data: item });
    g++;
  }
  console.log(`   ✓ ${g} hidden gems\n`);

  const total = d + h + g;
  console.log('╔══════════════════════════════════════════════════╗');
  console.log('║   ✅ Phase 1 Complete — Database Loaded!         ║');
  console.log('╠══════════════════════════════════════════════════╣');
  console.log(`║   📍 Destinations : ${d.toString().padEnd(27)}║`);
  console.log(`║   🏨 Hotels       : ${h.toString().padEnd(27)}║`);
  console.log(`║   💎 Hidden Gems  : ${g.toString().padEnd(27)}║`);
  console.log(`║   📊 TOTAL        : ${total.toString().padEnd(27)}║`);
  console.log('╠══════════════════════════════════════════════════╣');
  console.log('║   All provinces covered:                         ║');
  console.log('║   ICT • Punjab • Sindh • KPK • GB • AJK         ║');
  console.log('║   Balochistan • Murree/Galliyat                  ║');
  console.log('╚══════════════════════════════════════════════════╝\n');
  console.log('🚀 Next: npm run dev → http://localhost:5000/health\n');
}

main()
  .catch(e => { console.error('❌ Seed failed:', e.message); process.exit(1); })
  .finally(async () => { await prisma.$disconnect(); });
